<?php
declare(strict_types=1);

if($path==='/workflows'){
 require_permission('workflows.view');if($method==='POST'){require_permission('workflows.edit');verify_csrf();$action=(string)post('action');if($action==='toggle')db()->prepare('UPDATE workflows SET active=NOT active,updated_by=? WHERE id=?')->execute([user()['id'],(int)post('workflow_id')]);elseif($action==='stop')db()->prepare("UPDATE workflow_enrollments SET status='stopped',completed_at=NOW() WHERE id=? AND status='active'")->execute([(int)post('enrollment_id')]);audit($action,'workflow',(int)post('workflow_id'));redirect('/workflows');}$rows=db()->query("SELECT w.*,COUNT(e.id) enrollments,SUM(e.status='active') active_enrollments,SUM(e.status='failed') failed_enrollments FROM workflows w LEFT JOIN workflow_enrollments e ON e.workflow_id=w.id GROUP BY w.id ORDER BY w.updated_at DESC")->fetchAll();layout('Workflows',function()use($rows){?><div class="actions"><h1 style="margin:0">Workflows</h1><span class="spacer"></span><?php if(can('workflows.edit')):?><a class="btn" href="/workflows/new">Create workflow</a><?php endif?></div><div class="card"><p class="muted">Lightweight workflows run when a contact is created, tagged, submits a form, books, or changes opportunity stage. Actions execute in order and may pause for a configured wait.</p><table><thead><tr><th>Workflow</th><th>Trigger</th><th>Enrollments</th><th>Health</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $w):?><tr><td><a href="/workflows/<?=$w['id']?>"><strong><?=e($w['name'])?></strong></a></td><td><?=e(ucwords(str_replace('_',' ',$w['trigger_type'])))?></td><td><?=$w['enrollments']?> total · <?=$w['active_enrollments']?> active</td><td><?=$w['failed_enrollments']?'<span class="danger-text">'.$w['failed_enrollments'].' failed</span>':'Healthy'?></td><td><?=$w['active']?'Active':'Draft'?></td><td><?php if(can('workflows.edit')):?><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="workflow_id" value="<?=$w['id']?>"><button class="compact <?=$w['active']?'danger':'secondary'?>"><?=$w['active']?'Pause':'Activate'?></button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div><?php });exit;
}
if($path==='/workflows/new'||preg_match('#^/workflows/(\d+)/edit$#',$path,$m)){
 require_permission('workflows.edit');$id=(int)($m[1]??0);$w=null;if($id){$q=db()->prepare('SELECT * FROM workflows WHERE id=?');$q->execute([$id]);$w=$q->fetch();if(!$w){http_response_code(404);exit('Workflow not found');}}if($method==='POST'){verify_csrf();$name=trim((string)post('name'));$trigger=(string)post('trigger_type');$allowed=['contact_created','tag_added','form_submitted','booking_created','opportunity_stage_changed','manual'];$steps=json_decode((string)post('steps_json'),true);if($name===''||!in_array($trigger,$allowed,true)||!is_array($steps)||!$steps){flash('error','Enter a name, valid trigger, and at least one valid action.');}else{$cfg=[];$filter=(int)post('filter_id');if($filter)$cfg[match($trigger){'tag_added'=>'tag_id','form_submitted'=>'form_id','booking_created'=>'meeting_type_id',default=>'filter_id'}]=$filter;if($trigger==='opportunity_stage_changed'&&post('to_status')!=='')$cfg['to_status']=(string)post('to_status');if($id)db()->prepare('UPDATE workflows SET name=?,trigger_type=?,trigger_config=?,steps_json=?,updated_by=? WHERE id=?')->execute([$name,$trigger,json_encode($cfg),json_encode($steps),user()['id'],$id]);else{db()->prepare('INSERT INTO workflows(name,trigger_type,trigger_config,steps_json,created_by,updated_by) VALUES(?,?,?,?,?,?)')->execute([$name,$trigger,json_encode($cfg),json_encode($steps),user()['id'],user()['id']]);$id=(int)db()->lastInsertId();}audit($w?'update':'create','workflow',$id);flash('success','Workflow saved as a draft.');redirect('/workflows/'.$id);}}$tags=all_tags();$forms=db()->query('SELECT id,name FROM crm_forms WHERE active=1 ORDER BY name')->fetchAll();$meetings=db()->query('SELECT id,name FROM booking_meeting_types WHERE active=1 ORDER BY name')->fetchAll();$users=db()->query("SELECT id,COALESCE(NULLIF(display_name,''),username) name FROM users WHERE active=1 ORDER BY name")->fetchAll();layout($w?'Edit workflow':'Create workflow',function()use($w,$tags,$forms,$meetings,$users){?><h1><?=$w?'Edit workflow':'Create workflow'?></h1><form class="card" method="post" id="workflow-builder"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="steps_json" id="workflow-steps"><label>Name<input name="name" value="<?=e($w['name']??'')?>" required></label><div class="form-grid"><label>Trigger<select name="trigger_type" id="workflow-trigger"><?php foreach(['contact_created'=>'Contact created','tag_added'=>'Tag added','form_submitted'=>'Form submitted','booking_created'=>'Booking created','opportunity_stage_changed'=>'Opportunity stage changed','manual'=>'Manual enrollment'] as $code=>$label):?><option value="<?=$code?>" <?=($w['trigger_type']??'')===$code?'selected':''?>><?=$label?></option><?php endforeach?></select></label><label>Optional filter<select name="filter_id" id="workflow-filter"><option value="">Any</option></select></label><label>Opportunity destination stage<select name="to_status"><option value="">Any stage</option><?php foreach(list_options('opportunity_status') as $o):?><option value="<?=e($o['code'])?>"><?=e($o['label'])?></option><?php endforeach?></select></label></div><hr><div class="actions"><h2 style="margin:0">Actions</h2><button type="button" class="secondary" id="workflow-add-step">Add action</button></div><div id="workflow-step-list"></div><button>Save draft</button></form><script>window.workflowBuilder=<?=json_encode(['steps'=>json_decode((string)($w['steps_json']??'[]'),true)?:[],'config'=>json_decode((string)($w['trigger_config']??'[]'),true)?:[],'tags'=>array_map(fn($x)=>['id'=>$x['id'],'name'=>$x['name']],$tags),'forms'=>$forms,'meetings'=>$meetings,'users'=>$users],JSON_HEX_TAG|JSON_HEX_APOS|JSON_HEX_AMP|JSON_HEX_QUOT)?>;</script><script src="/assets/workflow-builder.js"></script><?php });exit;
}
if(preg_match('#^/workflows/(\d+)$#',$path,$m)){
 require_permission('workflows.view');$q=db()->prepare('SELECT * FROM workflows WHERE id=?');$q->execute([(int)$m[1]]);$w=$q->fetch();if(!$w){http_response_code(404);exit('Workflow not found');}if($method==='POST'){require_permission('workflows.edit');verify_csrf();if(post('action')==='enroll'){$cid=(int)post('contact_id');db()->prepare("INSERT INTO workflow_enrollments(workflow_id,contact_id,status,next_run_at) VALUES(?,?,'active',NOW())")->execute([$w['id'],$cid]);flash('success','Contact enrolled.');}elseif(post('action')==='stop')db()->prepare("UPDATE workflow_enrollments SET status='stopped',completed_at=NOW() WHERE id=? AND workflow_id=?")->execute([(int)post('enrollment_id'),$w['id']]);redirect('/workflows/'.$w['id']);}$q=db()->prepare("SELECT e.*,CONCAT(c.first_name,' ',c.last_name) contact_name FROM workflow_enrollments e JOIN contacts c ON c.id=e.contact_id WHERE e.workflow_id=? ORDER BY e.started_at DESC LIMIT 500");$q->execute([$w['id']]);$rows=$q->fetchAll();$contacts=db()->query("SELECT id,CONCAT(first_name,' ',last_name) name FROM contacts WHERE active=1 ORDER BY first_name,last_name LIMIT 2000")->fetchAll();layout($w['name'],function()use($w,$rows,$contacts){?><div class="actions"><h1 style="margin:0"><?=e($w['name'])?></h1><span class="spacer"></span><?php if(can('workflows.edit')):?><a class="btn" href="/workflows/<?=$w['id']?>/edit">Edit</a><?php endif?></div><div class="card"><strong>Trigger:</strong> <?=e(ucwords(str_replace('_',' ',$w['trigger_type'])))?> · <?=$w['active']?'Active':'Draft'?><pre><?=e(json_encode(json_decode($w['steps_json'],true),JSON_PRETTY_PRINT))?></pre></div><?php if(can('workflows.edit')):?><form class="card actions" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="enroll"><label style="flex:1">Manually enroll contact<select name="contact_id" required><option value="">Choose…</option><?php foreach($contacts as $c)if(contact_access((int)$c['id'])!=='hidden'):?><option value="<?=$c['id']?>"><?=e($c['name'])?></option><?php endif?></select></label><button>Enroll</button></form><?php endif?><div class="card"><h2>Enrollment history</h2><table><thead><tr><th>Contact</th><th>Status</th><th>Step</th><th>Next run</th><th>Error</th><th></th></tr></thead><tbody><?php foreach($rows as $e):?><tr><td><a href="/contacts/<?=$e['contact_id']?>"><?=e($e['contact_name'])?></a></td><td><?=e($e['status'])?></td><td><?=$e['current_step']?></td><td><?=e($e['next_run_at']?:'—')?></td><td><?=e($e['error_message'])?></td><td><?php if($e['status']==='active'):?><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="stop"><input type="hidden" name="enrollment_id" value="<?=$e['id']?>"><button class="danger compact">Stop</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div><?php });exit;
}
